import type { Frame, RegisterFrame } from "./types.js";

export class ProtocolValidationError extends Error {
  constructor(message: string, public readonly code = "INVALID_FRAME") {
    super(message);
    this.name = "ProtocolValidationError";
  }
}

export function validateRegisterFrame(frame: Frame): asserts frame is RegisterFrame {
  const record = frame as Record<string, unknown>;
  if (record.type !== "app_register" && record.type !== "backend_register") {
    throw new ProtocolValidationError(
      `Expected type "app_register" or "backend_register", got "${String(record.type)}"`,
      "INVALID_FRAME",
    );
  }

  if (record.type === "app_register") {
    if (typeof record.access_token !== "string" || record.access_token.trim() === "") {
      throw new ProtocolValidationError(
        `Frame requires non-empty access_token`,
        "INVALID_TOKEN",
      );
    }
    if (typeof record.terminal_label !== "string" || record.terminal_label.trim() === "") {
      throw new ProtocolValidationError(
        `Frame requires non-empty terminal_label`,
        "INVALID_FRAME",
      );
    }
    return;
  }

  if (typeof record.backend_id !== "string" || record.backend_id.trim() === "") {
    throw new ProtocolValidationError(
      `Frame requires non-empty backend_id`,
      "INVALID_FRAME",
    );
  }
  if (typeof record.backend_label !== "string" || record.backend_label.trim() === "") {
    throw new ProtocolValidationError(
      `Frame requires non-empty backend_label`,
      "INVALID_FRAME",
    );
  }
}

export function getStringField(frame: Frame, field: string): string {
  const value = (frame as Record<string, unknown>)[field];
  if (typeof value !== "string" || value.trim() === "") {
    throw new ProtocolValidationError(
      `Frame requires string field "${field}"`,
      "INVALID_FRAME",
    );
  }
  return value;
}
